// Load processed conversations from static data or initialize
const processedFile = '/home/clawdbot/dev-sandbox/projects/marceau-solutions/labs/ai-phone-agent/data/processed_conversations.json';
const fs = require('fs');

let processed = [];
try {
  processed = JSON.parse(fs.readFileSync(processedFile, 'utf8'));
} catch (e) {
  processed = [];
}

const conversations = $input.first().json.conversations || [];
const newConversations = conversations.filter(c => 
  !processed.includes(c.conversation_id) && 
  c.call_duration_secs >= 10
);

return newConversations.map(c => ({ json: c }));

const conv = $input.first().json;
const transcript = conv.transcript || [];

// Parse transcript for key info
let name = null;
let phone = null;
let callbackRequested = false;
let keyMessage = null;

const fullText = transcript
  .filter(t => t.message && t.message !== '...')
  .map(t => `${t.role}: ${t.message}`)
  .join('\n');

// Extract name
const nameMatch = fullText.match(/(?:my name is|this is|i'm|i am) ([A-Z][a-z]+ ?[A-Z]?[a-z]*)/i);
if (nameMatch) name = nameMatch[1].trim();

// Extract phone
const phoneMatch = fullText.match(/(\d{3}[-.]?\d{3}[-.]?\d{4})/);
if (phoneMatch) phone = phoneMatch[1];

// Check for callback request
if (/call back|call me back|give me a call|return my call/i.test(fullText)) {
  callbackRequested = true;
}

// Get first substantive user message
for (const turn of transcript) {
  if (turn.role === 'user' && turn.message && turn.message !== '...' && turn.message.length > 20) {
    keyMessage = turn.message.substring(0, 200);
    break;
  }
}

// Calculate score
let score = 0;
const reasons = [];
const duration = conv.metadata?.call_duration_secs || 0;

if (duration >= 120) { score += 30; reasons.push(`Long call (${duration}s)`); }
else if (duration >= 60) { score += 20; reasons.push(`Good engagement (${duration}s)`); }
else if (duration >= 30) { score += 10; }

if (callbackRequested) { score += 30; reasons.push('Callback requested'); }
if (name) { score += 15; reasons.push(`Name: ${name}`); }
if (phone) { score += 10; reasons.push(`Phone: ${phone}`); }

const messageCount = transcript.filter(t => t.message !== '...').length;
if (messageCount >= 6) { score += 20; reasons.push(`Active (${messageCount} msgs)`); }

let priority = 'low';
if (score >= 60) priority = 'hot';
else if (score >= 30) priority = 'warm';
else if (score >= 15) priority = 'cold';

const emoji = { hot: '🔥', warm: '☀️', cold: '❄️', low: '⚪' }[priority];

return [{
  json: {
    conversation_id: conv.conversation_id,
    caller: conv.user_id,
    duration: duration,
    score: Math.min(score, 100),
    priority: priority,
    emoji: emoji,
    name: name,
    phone: phone,
    callbackRequested: callbackRequested,
    keyMessage: keyMessage,
    summary: conv.analysis?.transcript_summary || '',
    title: conv.analysis?.call_summary_title || 'Call',
    reasons: reasons,
    timestamp: new Date(conv.metadata?.start_time_unix_secs * 1000).toISOString(),
    followUp: score >= 30
  }
}];

// Mark conversation as processed
const processedFile = '/home/clawdbot/dev-sandbox/projects/marceau-solutions/labs/ai-phone-agent/data/processed_conversations.json';
const fs = require('fs');

let processed = [];
try {
  processed = JSON.parse(fs.readFileSync(processedFile, 'utf8'));
} catch (e) {
  processed = [];
}

const convId = $input.first().json.conversation_id;
if (!processed.includes(convId)) {
  processed.push(convId);
  fs.writeFileSync(processedFile, JSON.stringify(processed));
}

return $input.all();
